#include<bits/stdc++.h>
using namespace std;
string s1,s2;
void findroot(string tree){
	if(!tree.size())return;
	int w;
	for(int i=s2.size()-1;i>=0;i--){
		w=tree.find(s2[i]);
		if(w!=-1){
			break;
		}
	}
	cout<<tree[w];
	findroot(tree.substr(0,w));
	findroot(tree.substr(w+1));
}
int main(){
    
    cin>>s1>>s2;
    findroot(s1);
    
}
